+    \\
+    \\    const worker = new Worker(URL.createObjectURL(workerBlob));
+    \\    workers.set(id, { worker, done: false, result: null });
+    \\
+    \\    worker.onmessage = (e) => {
+    \\        const state = workers.get(e.data.id);
+    \\        if (state) {
+    \\            state.done = true;
+    \\            state.result = e.data.result;
